from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, format='%(asctime)s - %(message)s')

# Dummy user database
users = {
    "user1": {"password": "password1", "email": "user1@example.com"},
    "user2": {"password": "password2", "email": "user2@example.com"},
}

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')
    
    if username in users and users[username]['password'] == password:
        logging.info(f'Successful login attempt: Username: {username}, Email: {users[username]["email"]}, IP: {ip_address}, User-Agent: {user_agent}')
        return jsonify({"message": "Login successful"}), 200
    else:
        logging.info(f'Failed login attempt: Username: {username}, IP: {ip_address}, User-Agent: {user_agent}')
        return jsonify({"message": "Invalid credentials"}), 401

if __name__ == '__main__':
    app.run(debug=True)